import { Box, Circle, Flex } from '@chakra-ui/react';
import { ActionPagesQueryParams } from '@state/action_pages';
import { useTags } from '@state/tags';
import { CheckmarkIcon } from '@ui/assets/icons/CheckmarkIcon';
import { CloseIcon } from '@ui/assets/icons/CloseIcon';
import { SearchInputControl } from '@ui/components/formControls/InputControl/components/SearchInputControl';
import { Loading } from '@ui/components/Loading';
import { RoundedVStack } from '@ui/components/RoundedStack';
import { Label, Meta } from '@ui/components/typography';
import { makeFilter } from '@ui/utils/makeFilter';
import { useState } from 'react';
import { useFormContext } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { useInView } from 'react-intersection-observer';
import { ActionPagesFilterFormShape, TagsFilterForm } from '../types';

export const tagsFilter = makeFilter<TagsFilterForm, ActionPagesQueryParams>(
  ['accessTags'],
  { selectedTagNames: [] },
  ({ selectedTagNames }) => ({ accessTags: selectedTagNames?.join(',') }),
  ({ accessTags }) => ({ selectedTagNames: accessTags?.split(',') })
);

export const TagsFilter = () => {
  const { t } = useTranslation('actionPages', { keyPrefix: 'filter.tags' });
  const [searchTerm, setSearchTerm] = useState('');
  const { setValue, watch } = useFormContext<ActionPagesFilterFormShape>();
  const { fetchMoreTags, hasMoreTags, tags } = useTags({ searchTerm });
  const selectedTagNames = watch('selectedTagNames');

  const { ref } = useInView({
    onChange(inView) {
      if (inView) {
        fetchMoreTags();
      }
    },
    triggerOnce: false,
  });

  const selectTag = (name: string) =>
    setValue('selectedTagNames', (selectedTagNames ?? []).concat(name));
  const deselectTag = (name: string) =>
    setValue(
      'selectedTagNames',
      selectedTagNames?.filter((tagName) => tagName !== name)
    );

  return (
    <RoundedVStack>
      <Box borderWidth="1px" pb={2} pt={4} px={4}>
        <SearchInputControl
          changeQueryFilter={(_k, val) =>
            setSearchTerm(Array.isArray(val) ? val.join(',') : (val ?? ''))
          }
          placeholder={t('placeholder')}
          variant="outline"
        />
      </Box>
      <Flex
        borderWidth="1px"
        direction="column"
        gap={2}
        h="200px"
        overflow="hidden"
        overflowY="scroll"
        pt={4}
        px={4}
      >
        {tags && tags.length ? (
          tags?.map(({ color, description, id, name }) => {
            const isSelected = name && selectedTagNames?.includes(name);

            return (
              <Flex cursor="pointer" gap={2} key={id} onClick={() => name && selectTag(name)}>
                <Box h={6} w={6}>
                  {isSelected && <CheckmarkIcon />}
                </Box>
                <Circle bg={color} mt={1} size="15px" />
                <Box w="full">
                  <Meta>{name}</Meta>
                  <Meta color="neutral.500">{description}</Meta>
                </Box>
                <Box h={6} w={6}>
                  {isSelected && (
                    <CloseIcon
                      cursor="pointer"
                      onClick={(e) => {
                        e.stopPropagation();
                        deselectTag(name);
                      }}
                    />
                  )}
                </Box>
              </Flex>
            );
          })
        ) : (
          <Label color="neutral.500" textAlign="center" w="full">
            {t('noResults')}
          </Label>
        )}
        {hasMoreTags && (
          <Box py={4} ref={ref}>
            <Loading />
          </Box>
        )}
      </Flex>
    </RoundedVStack>
  );
};

